var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"으아앙-! 과자, 내 과자가!","JPN":"うわーん！　お菓子、私のお菓子が！","ENG":"Waaah! My snack!","TWN":"啊啊啊——！餅乾，我的餅乾！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"어… 죄송해요. 접대용인 줄 알고 그만.","JPN":"あっ……すみません。接待用のお菓子だと勘違いしていました。","ENG":"Uh... I'm sorry. I thought it was for the guests.","TWN":"喔……抱歉。我以為是招待用的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"제가 더 좋은 걸 드릴 테니 이번 한 번은 참아주세요.","JPN":"もっといいお菓子を用意しますから、許してください。","ENG":"I'll give you something better. Please let this slide, won't you?","TWN":"姊姊拿更好的東西和你換吧，對不起啦。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"매워어-! 누나, 유피 누나아아아-!!","JPN":"からーい！　お姉ちゃん、ユピのお姉ちゃーん！！","ENG":"It's spicyyyyy! Yuppie! Yuppieeeeee!","TWN":"好辣喔——！姊姊，悠菲姊姊——！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아 쫌! 사고친지 얼마나 지났다고 또 그러시는 거예요, 선배는?","JPN":"もう、ついこの前問題を起したばかりだっていうのに、今度は何をしたんですか、先輩！","ENG":"Oh, c'mon! You already caused another problem?!","TWN":"前輩真是的！才剛闖禍沒多久，你又這樣？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"죄송해요. 저는 그냥 아이들에게 선물을 했을 뿐인데…….","JPN":"すみません。ただ子どもたちにプレゼントをしただけなんですが……","ENG":"I'm sorry. I was just trying to give presents to the children...","TWN":"對不起，我只是給孩子們送點禮物而已……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"설마 방울토마토를 싫어하는 아이가 있을 줄은 몰랐어요.","JPN":"まさかミニトマトが嫌いな子どもがいるなんて、想像していなくて。","ENG":"But I didn't think children would hate cherry tomatoes.","TWN":"沒想到竟然會有孩子不喜歡小番茄。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네? 그럴 리가요. 오스틴이 토마토를 얼마나-","JPN":"え？　オスティンはトマトが大好きで……","ENG":"Huh? That's weird. Austin loves tomatoes–","TWN":"呃？怎麼可能。奧斯丁很喜歡番茄的？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"선배. 애한테 이걸 먹인 거예요?","JPN":"先輩。まさかこれを子どもたちに食べさせたんですか？","ENG":"Wait. Did you give this to a child?","TWN":"前輩，你給孩子吃的是這個？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"네. 빨갛고~ 동그랗고~ 아삭아삭한 식감의~","JPN":"はい。真っ赤で、まん丸で、歯ごたえのあるー","ENG":"Yes. It's red, round, and crunchy!","TWN":"沒錯，紅紅的～圓圓的～脆脆的口感～"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"부트 졸로키아잖아! 애한테 이런 걸 먹이면 어떡해요?","JPN":"これ、ブートジョロキアじゃないですか！　子どもにこんなものあげちゃダメですよ！","ENG":"It's a ghost pepper! You can't give ghost peppers to a kid!","TWN":"這是鬼辣矮！怎麼能給孩子吃這種東西呢？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"위, 위장약! 위장약이 어디 있지? 아니 그 전에 우유부터…!","JPN":"い、胃腸薬！　胃腸薬はどこ？　いや、その前に牛乳を……！","ENG":"M-medicine! Where's the first aid kit?! No, maybe milk first...?!","TWN":"胃、胃藥！胃藥在哪裡？不，先找牛奶……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"으음… 역시 아이들은 토마토보다는 과자를 좋아하는 걸까요?","JPN":"はあ……やっぱり子どもたちにはトマトよりお菓子の方がいいのでしょうか？","ENG":"Hmm... I guess children like sweets more than tomatoes.","TWN":"嗯……果然孩子們還是更喜歡零食而不是番茄嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"아, 여기서 동물 모양 과자를 팔면 엄청 인기 있을지도?","JPN":"あ、ここで動物の形をしたお菓子を売れば、人気が出るかも！","ENG":"Maybe I can sell animal-shaped cookies here.","TWN":"如果在這裡賣動物形狀的餅乾，肯定會很受歡迎吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"동물보다 귀여운 크레데레는 어떠신가요, 언니. 분명 품절대란이 일어날 겁니다.","JPN":"動物より、可愛いクレデレはいかがですか、お姉さん。きっと品切れが続出すると思いますよ。","ENG":"How do you feel about Credere-shaped cookies? People will be hoarding them.","TWN":"比動物更可愛的克蕾妲莉餅乾怎麼樣，姊姊？肯定會熱賣的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"후후. 두 명에게는 유감이지만 이미 제 대포곡물시리얼튀김이 시장을 선점했답니다.","JPN":"ふふ、お二人には申し訳ない話ですが、ここではもうすでに私の大砲穀物シリアル揚げが確固たる地位を築いるんです。","ENG":"Hu huu. I'm sorry to tell you both that my fried cannon-grain-cereal has already dominated the market.","TWN":"呵呵，雖然對你們感到很抱歉，但我的大砲轟炸穀物已經佔領了市場！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"무려 그라운드 원에서부터 시작된 유서 깊은 초인기전통과자라고요! 다들 맛이 어떠신가요?","JPN":"なんとグラウンド・ワンから始まった由緒正しき伝統菓子なんです！　みなさん、お味はいかがですか？","ENG":"It's a super popular traditional snack that originated in Ground One! What do you all think?","TWN":"這可是從G1傳過來的超人氣點心喔！大家覺得味道怎麼樣？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"이건 그냥 평범한 팝콘이잖아. 유피 누나가 만든 과자가 더 맛있어.","JPN":"こんなのただのポップコーンじゃない。ユピ姉さんが作ったお菓子の方が美味しいよ。","ENG":"It's just popcorn. I like Yuppie's snacks better.","TWN":"這只是普通的爆米花嘛。悠菲姊姊做的點心更好吃。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"맞아. 언니 과자는 귀여운데 이건 모양도 이상해.","JPN":"そうだ。お姉ちゃんのお菓子は見た目も可愛いのに、これは見た目も変だよ。","ENG":"Yeah. Her snacks look cute, but this one has a weird shape.","TWN":"對啊。姊姊的餅乾很可愛，但這個形狀好奇怪。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"이 무슨 불경한 소리를…! 제 개인명의로 된 사업상품이 그깟 수제 과자만 못하다고요?","JPN":"なんて侮辱発言……！　うちの商品が、あんなただの手作りお菓子に負けているですって？","ENG":"Blasphemy...! You think the business product under my own name is worse than some homemade snack?","TWN":"這是什麼鬼話……！意思是以我個人名義經營的商業產品還不如一塊手工餅乾嗎！？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L30_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"과연, 과자에 뭔가 얄팍한 수를 부린 게 분명해요! 터커랑 다닐 때부터 알아봤어야 했는데!","JPN":"なるほど、ならばきっとお菓子に何かよからぬ手を加えているに違いありません！　ターカーとつるんでいるくらいだし、やっぱりといった感じです！","ENG":"She must've done something with the snacks! I should've known she was up to no good from the moment I saw her with Tucker!","TWN":"果然，是不是有在餅乾裡加什麼東西！和塔克在一起時就該看出來的！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"기다려요, 크레데레! 이 언니가 악의 손아귀로부터 구해드릴게요!","JPN":"待っていてください、クレデレ！　私が悪の巣窟から救い出してあげますわ！","ENG":"Just you wait, Credere! I will save you from the jaws of evil!","TWN":"等著瞧，克蕾妲莉！姊姊我會把你從邪惡的魔爪中救出來的！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"대포는 또 어디서 난 거야! 분명 보육원 들어오기 전에 다 압수했잖아요?","JPN":"銃なんてどこで手に入れたんですか？　入園する前にちゃんとチェックしたはずなのに！","ENG":"Where did you get that cannon?! I took all your weapons before you entered the orphanage!","TWN":"這大炮又是從哪裡弄來的！我明明在進育幼院之前都沒收掉的？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"보스! 부탁했던 물건들 다 빼돌렸어요! 저 잘했죠?","JPN":"ボス！　頼まれたものはすべて秘密裏に隠しておきました！　褒めてください！","ENG":"Boss! I smuggled out all the things you wanted me to! Did I do a good job?","TWN":"老大！你要的東西都偷出來了！我做得不錯吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"굿잡입니다, 부하 14호. 미스터 쮸빕도 부활했으니 이제 간식 창고를 털러 가죠.","JPN":"グッジョブです、部下14号。ミスター・チュピーも復活したので、これからおやつ倉庫を荒らしに行きましょう。","ENG":"Good job, Underling No.14. Since Mr. Squirty is back, we can now go raid the snack room.","TWN":"做得很好，14號手下。既然咻咻先生也復活了，現在我們去打劫零食倉庫吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L38_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레는 곧 죽어도 오늘 딸기우유에 슈크림빵을 먹어야겠습니다.","JPN":"クレデレは何があっても今日、イチゴ牛乳とクリームパンを食べたいのです。","ENG":"Credere will not let the day pass without having some strawberry milk and cream puffs.","TWN":"就算是死，克蕾妲莉今天也要喝到草莓牛奶配奶油麵包。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"인마들아-. 오늘은 크레데레님이 지정한 축제 날이다-.","JPN":"野郎ども～今日はクレデレ様が決めた祭日だぞ～！","ENG":"Kids, Credere hereby declares this day as an official festival day.","TWN":"喂～大家聽著，今天是克蕾妲莉老大指定的節日～"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"제일 많이 먹은 녀석에게는 칭찬도장 하나를 주겠다, 이 말이야-.","JPN":"一番たくさん食べた子には、よくできましたハンコを押してあげよう。","ENG":"The kid who eats the most gets a stamp.","TWN":"吃得最多的人會得到一個好寶寶印章，就這麼說定了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"와아! 저 진짜 많이 먹을 수 있어요, 보스!","JPN":"わーい！　私、たくさん食べられます、ボス！","ENG":"Whoa! I can eat sooo much, boss!","TWN":"哇！我可以吃很多的，老大！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_CHILD"},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"축제면 밥 먹고 양치질 안 해도 되겠다. 아싸!","JPN":"お祭りなら、歯磨きしなくてもいいよね。やったー！","ENG":"I can eat without brushing my teeth if this is a festival! Cool!","TWN":"既然是節日，吃完飯就不用刷牙了，耶！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"허.","JPN":"はぁ。","ENG":"Huh.","TWN":"嘖。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"자식농사 대박이네, 진짜.","JPN":"これから子どもたちがどうなるか心配だね。","ENG":"Such sisters. Wow!","TWN":"還真會教小孩，真是的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};